function solve(n) {
    // Function to convert a number to a given base (hex or base36)
    function convertToBase(num, base) {
        if (num === 0) return '0';
        const digits = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';
        let result = '';
        while (num > 0) {
            const remainder = num % base;
            result = digits[remainder] + result;
            num = Math.floor(num / base);
        }
        return result;
    }

    // Calculate n squared and n cubed
    const nSquared = n * n;
    const nCubed = n * n * n;

    // Convert to hexadecimal and base36
    const hex = convertToBase(nSquared, 16);
    const base36 = convertToBase(nCubed, 36);

    // Concatenate and return the result
    return hex + base36;
}
